  1185 | /// WARNING: only if canFreelyInvertAllUsersOf() said this can be done.
  1186 | void InstCombinerImpl::freelyInvertAllUsersOf(Value *I, Value *IgnoredUser) {
  1187 |   assert(!isa<Constant>(I) && "Shouldn't invert users of constant");
